value.stringValue:
AND(
ISPICKVAL([Case].Origin, 'Email'), ISPICKVAL([Case].Status, 'New'), [Case].RecordType.DeveloperName = 'IHG_Ignite_Case', NOT( OR( CONTAINS(UPPER([Case].Subject), 'OUT OF OFFICE'), CONTAINS(UPPER([Case].Subject), 'OOO'), CONTAINS(UPPER([Case].Subject), 'VACATION'), CONTAINS(UPPER([Case].Subject), 'PAID TIME OFF'), CONTAINS(UPPER([Case].Subject), 'PTO'), CONTAINS(UPPER([Case].Subject), 'HOLIDAY'), CONTAINS(UPPER([Case].Subject), 'AUTO') )
) )

formulas.expression:
AND(
ISPICKVAL({!myVariable_current.Origin}, 'Email'), ISPICKVAL({!myVariable_current.Status}, 'New'), {!myVariable_current.RecordType.DeveloperName} = 'IHG_Ignite_Case', NOT( OR( CONTAINS(UPPER({!myVariable_current.Subject}), 'OUT OF OFFICE'), CONTAINS(UPPER({!myVariable_current.Subject}), 'OOO'), CONTAINS(UPPER({!myVariable_current.Subject}), 'VACATION'), CONTAINS(UPPER({!myVariable_current.Subject}), 'PAID TIME OFF'), CONTAINS(UPPER({!myVariable_current.Subject}), 'PTO'), CONTAINS(UPPER({!myVariable_current.Subject}), 'HOLIDAY'), CONTAINS(UPPER({!myVariable_current.Subject}), 'AUTO') )
) )
